CREATE TABLE IF NOT EXISTS Utenti(username VARCHAR(254) PRIMARY KEY, email VARCHAR(254) NOT NULL, password VARCHAR(254) NOT NULL); 
CREATE TABLE IF NOT EXISTS Avventure(id INT AUTO_INCREMENT PRIMARY KEY, titolo VARCHAR(100) NOT NULL, id_master VARCHAR(254), FOREIGN KEY (id_master) REFERENCES Utenti(username) ON UPDATE CASCADE ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS GicatoreAvventura(user VARCHAR(254), id_avventura INT, FOREIGN KEY (user) REFERENCES Utenti(username) ON UPDATE CASCADE ON DELETE CASCADE, FOREIGN KEY (id_avventura) REFERENCES Avventure(id) ON UPDATE CASCADE ON DELETE CASCADE, PRIMARY KEY(user, id_avventura));  
CREATE TABLE IF NOT EXISTS Personaggi(id INT AUTO_INCREMENT PRIMARY KEY, nome VARCHAR(100) NOT NULL, livello INT NOT NULL, classe VARCHAR(32) NOT NULL, razza VARCHAR(32) NOT NULL, FORZA INT NOT NULL, DESTRETTA INT NOT NULL, COSTITUZIONE INT NOT NULL, INTELLIGENZA INT NOT NULL, SAGGEZZA INT NOT NULL, CARISMA INT NOT NULL, id_utente VARCHAR(254), FOREIGN KEY (id_utente) REFERENCES Utenti(username) ON UPDATE CASCADE ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS Contenuti(id INT AUTO_INCREMENT PRIMARY KEY, data_creazione DATE NOT NULL, id_master VARCHAR(254), n_parole INT, dimensioni INT, FOREIGN KEY (id_master) REFERENCES Utenti(username) ON UPDATE CASCADE ON DELETE CASCADE); 
CREATE TABLE IF NOT EXISTS Partite(id_avventura INT, numero INT, data_svolgimento DATE NOT NULL, PRIMARY KEY(id_avventura, numero), FOREIGN KEY (id_avventura) REFERENCES Avventure(id) ON UPDATE CASCADE ON DELETE CASCADE);